import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import api from "../../api/axios"; // ✅ IMPORTANT

const AppointmentList = () => {
  const [appointments, setAppointments] = useState([]);

  useEffect(() => {
    const fetchAppointments = async () => {
      try {
        const res = await api.get("/appointments"); // ✅ token auto attached
        setAppointments(res.data);
      } catch (err) {
        console.error("Fetch appointments failed:", err.response?.data || err.message);
        alert(err.response?.data?.message || "Failed to load appointments");
      }
    };
    fetchAppointments();
  }, []);

  const deleteAppointment = async (id) => {
    if (!window.confirm("Are you sure you want to delete this appointment?")) return;
    try {
      await api.delete(`/appointments/${id}`); // ✅ token auto attached
      setAppointments((prev) => prev.filter((a) => a._id !== id));
    } catch (err) {
      console.error("Delete appointment failed:", err.response?.data || err.message);
      alert(err.response?.data?.message || "Failed to delete appointment");
    }
  };

  return (
    <div style={{ padding: 20 }}>
      <h2>Appointments</h2>
      <Link to="/appointments/add">
        <button style={{ marginBottom: 20 }}>+ Add Appointment</button>
      </Link>

      <table border="1" cellPadding="10" style={{ width: "100%", textAlign: "left" }}>
        <thead>
          <tr>
            <th>Lead</th>
            <th>Vehicle</th>
            <th>Date</th>
            <th>Time</th>
            <th>Status</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {appointments.map((a) => (
            <tr key={a._id}>
              <td>{a.lead?.name || "-"}</td>
              <td>
                {a.vehicle?.brand ? `${a.vehicle.brand} ${a.vehicle.model || ""}` : "-"}
              </td>
              <td>{a.date ? new Date(a.date).toLocaleDateString() : "-"}</td>
              <td>{a.time || "-"}</td>
              <td>{a.status}</td>
              <td>
                <Link to={`/appointments/edit/${a._id}`}><button>Edit</button></Link>
                <button onClick={() => deleteAppointment(a._id)} style={{ marginLeft: 5 }}>
                  Delete
                </button>
              </td>
            </tr>
          ))}
          {appointments.length === 0 && (
            <tr>
              <td colSpan="6">No appointments found</td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
};

export default AppointmentList;
